"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content:
      "Set up your email address and a secure password to get started with your new account.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
    content:
      "Tell us about yourself. Add your name, bio, and profile picture to personalize your experience.",
  },
  {
    step: 3,
    title: "Review",
    description: "Review and confirm",
    content:
      "Everything looks good! Review your information below and confirm to complete your setup.",
  },
]

export default function StepperDemo() {
  const [currentStep, setCurrentStep] = React.useState(1)

  return (
    <div className="w-full max-w-xl space-y-6 p-6">
      <Stepper value={currentStep} onValueChange={setCurrentStep}>
        {/* Step indicators */}
        <div className="flex items-center">
          {steps.map((item, index) => (
            <React.Fragment key={item.step}>
              <StepperItem step={item.step}>
                <StepperTrigger>
                  <div className="flex flex-col items-start gap-0.5">
                    <StepperTitle>{item.title}</StepperTitle>
                    <StepperDescription>{item.description}</StepperDescription>
                  </div>
                </StepperTrigger>
              </StepperItem>
              {index < steps.length - 1 && (
                <StepperSeparator step={item.step} className="mx-2" />
              )}
            </React.Fragment>
          ))}
        </div>

        {/* Step panels */}
        {steps.map((item) => (
          <StepperPanel
            key={item.step}
            step={item.step}
            className="rounded-lg border p-6"
          >
            <h3 className="text-base font-semibold">{item.title}</h3>
            <p className="mt-1.5 text-sm text-muted-foreground">
              {item.content}
            </p>
          </StepperPanel>
        ))}
      </Stepper>

      {/* Navigation */}
      <div className="flex items-center justify-between">
        <Button
          variant="outline"
          onClick={() => setCurrentStep((s) => Math.max(1, s - 1))}
          disabled={currentStep === 1}
        >
          Previous
        </Button>
        <span className="text-sm text-muted-foreground">
          Step {currentStep} of {steps.length}
        </span>
        <Button
          onClick={() => setCurrentStep((s) => Math.min(steps.length, s + 1))}
          disabled={currentStep === steps.length}
        >
          {currentStep === steps.length ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}

