"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ── Contexts ──────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"

interface StepperContextValue {
  value: number
  onValueChange: (step: number) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext(): StepperContextValue {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error(
      "Stepper sub-components must be rendered inside a <Stepper />."
    )
  }
  return ctx
}

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItemContext(): StepperItemContextValue {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error(
      "StepperItem sub-components must be rendered inside a <StepperItem />."
    )
  }
  return ctx
}

// ── Stepper ───────────────────────────────────────────────────────────────────

function Stepper({
  value: valueProp,
  defaultValue = 1,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: number
  defaultValue?: number
  onValueChange?: (value: number) => void
  orientation?: StepperOrientation
}) {
  const [uncontrolledValue, setUncontrolledValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : uncontrolledValue

  const handleValueChange = React.useCallback(
    (step: number) => {
      if (!isControlled) setUncontrolledValue(step)
      onValueChange?.(step)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ── StepperItem ───────────────────────────────────────────────────────────────

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { value, orientation } = useStepperContext()
  const isActive = value === step
  const isCompleted = value > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex flex-col",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ── StepperTrigger ────────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepperContext()
  const { step, isActive, isCompleted } = useStepperItemContext()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      aria-current={isActive ? "step" : undefined}
      aria-selected={isActive}
      onClick={() => onValueChange(step)}
      className={cn(
        "inline-flex cursor-pointer items-center gap-2.5 rounded-md",
        "text-sm font-medium transition-colors outline-none",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        isActive || isCompleted ? "text-foreground" : "text-muted-foreground",
        "hover:text-foreground",
        className
      )}
      {...props}
    >
      <span
        aria-hidden
        className={cn(
          "flex size-7 shrink-0 items-center justify-center rounded-full border-2",
          "text-xs font-semibold transition-colors duration-300",
          isCompleted
            ? "border-primary bg-primary text-primary-foreground"
            : isActive
              ? "border-primary bg-background text-primary"
              : "border-border bg-background text-muted-foreground"
        )}
      >
        {isCompleted ? <CheckIcon className="size-3.5" /> : step}
      </span>
      {children}
    </button>
  )
}

// ── StepperTitle ──────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ── StepperDescription ────────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ── StepperSeparator ──────────────────────────────────────────────────────────

function StepperSeparator({
  step: stepProp,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  step?: number
}) {
  const { value, orientation } = useStepperContext()
  const isCompleted = stepProp !== undefined ? value > stepProp : false

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "incomplete"}
      aria-hidden
      className={cn(
        "rounded-full transition-colors duration-300",
        orientation === "horizontal"
          ? "h-0.5 min-w-4 flex-1 self-center"
          : "ms-[1.125rem] h-6 w-px self-start",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

// ── StepperPanel ──────────────────────────────────────────────────────────────

function StepperPanel({
  step: stepProp,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  step?: number
}) {
  const { value } = useStepperContext()
  const itemCtx = React.useContext(StepperItemContext)
  const step = stepProp ?? itemCtx?.step

  if (step === undefined) {
    throw new Error(
      "StepperPanel requires a `step` prop or must be rendered inside a <StepperItem />."
    )
  }

  const isActive = value === step

  return (
    <div
      data-slot="stepper-panel"
      data-state={isActive ? "active" : "inactive"}
      hidden={!isActive}
      className={cn("w-full", className)}
      {...props}
    />
  )
}

// ── Exports ───────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
}
